import{_ as a,v as t,f as o,i as r}from"./chunks/framework.jfF5glnW.js";const h=JSON.parse('{"title":"Week 3 | 继续练习 SolidWorks 复杂零件","description":"","frontmatter":{"title":"Week 3 | 继续练习 SolidWorks 复杂零件","date":"2026-03-17T00:00:00.000Z","tags":["课程周志","SolidWorks","复杂零件"],"cover":"/code2real_blog/posts/week3/water.webp"},"headers":[],"relativePath":"posts/week3.md","filePath":"posts/week3.md"}'),s={name:"posts/week3.md"};function l(i,e,p,d,n,c){return t(),o("div",null,[...e[0]||(e[0]=[r('<p>第三周继续进行 SolidWorks 建模训练。本周的重点从基础命令转向更复杂的草图关系、孔位定位以及多特征组合。</p><hr><img src="/code2real_blog/posts/week3/water.webp" alt="Week 3 image"><h2 id="本周学习内容" tabindex="-1">本周学习内容 <a class="header-anchor" href="#本周学习内容" aria-label="Permalink to &quot;本周学习内容&quot;">​</a></h2><p>本周的练习仍以 SolidWorks 为主，但模型复杂度明显提高。草图中开始出现更多圆弧、倒角、孔位和转折边，尺寸之间的关联也更密集。相比第二周的基础建模，本周更强调零件结构是否合理，而不是单纯把外形画出来。</p><p>重点练习了复杂轮廓草图、孔位约束、局部拉伸切除、圆角处理以及多步骤特征叠加。实际操作中能明显感受到，复杂零件不是靠某一个命令完成的，而是靠清晰的基准、稳定的草图和合适的建模顺序逐步建立。</p><h2 id="实践过程" tabindex="-1">实践过程 <a class="header-anchor" href="#实践过程" aria-label="Permalink to &quot;实践过程&quot;">​</a></h2><p>练习开始时，我先处理尺寸关系较多的二维草图。圆心位置、边界距离和线段连接关系都需要提前考虑，否则后续拉伸或切除时容易出现轮廓不闭合、尺寸冲突等问题。</p><p>进入三维建模后，我开始有意识地拆分步骤：先做主体，再处理孔位和局部细节，最后补充圆角或过渡特征。这样做虽然步骤更多，但修改起来更清楚。如果一开始就把细节全部堆上去，后面调整主体尺寸时会很混乱。</p><h2 id="遇到的问题" tabindex="-1">遇到的问题 <a class="header-anchor" href="#遇到的问题" aria-label="Permalink to &quot;遇到的问题&quot;">​</a></h2><p>本周最明显的问题是错误定位变难。草图复杂以后，问题不一定直接表现为形状画错，而是出现在生成特征时，例如轮廓无法选中、切除方向不对，或某个尺寸修改后牵动了其他结构。</p><p>另一个问题是容易只追求外观相似，忽略结构本身是否合理。比如孔位距离边缘太近、局部厚度偏薄、圆角位置提前加入，都会影响模型后续修改。这个阶段开始意识到，建模不能只看当前结果，还要考虑后面是否能继续调整。</p><h2 id="本周收获" tabindex="-1">本周收获 <a class="header-anchor" href="#本周收获" aria-label="Permalink to &quot;本周收获&quot;">​</a></h2><p>第三周让我对“复杂零件”的理解更具体了。复杂并不只是形状变多，而是尺寸关系、特征顺序和结构逻辑同时变多。</p><p>本周最大的收获是开始养成分层建模的习惯：先确定主体结构，再补充功能细节，最后处理修饰特征。这个顺序更稳，也更符合后续制造和修改的需要。</p><hr><img src="/code2real_blog/posts/week3/1.png" alt="Week 3 image"><img src="/code2real_blog/posts/week3/2.png" alt="Week 3 image">',18)])])}const k=a(s,[["render",l]]);export{h as __pageData,k as default};
